import React, { useState } from 'react';
import { Button, Input, Modal, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { sxService } from '../../../services/sx/sxService';
import type { ProductionStageDto } from '../../../services/sx/models';
import styles from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const emptyStage = { code: '', name: '', sequenceNo: 1, isActive: true };

const CongDoanPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const [stages, setStages] = useState<ProductionStageDto[]>([]);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<ProductionStageDto | null>(null);
  const [form, setForm] = useState(emptyStage);
  const [saving, setSaving] = useState(false);

  const load = () => {
    setLoading(true);
    sxService
      .getStages()
      .then(setStages)
      .catch(err => dispatch(addToast({ message: err?.message ?? 'Lỗi tải công đoạn', type: 'error' })))
      .finally(() => setLoading(false));
  };
  const handleSearch = () => setSearch(searchDraft.trim());
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const openAdd = () => {
    setEditing(null);
    setForm(emptyStage);
    setModalOpen(true);
  };

  const openEdit = (s: ProductionStageDto) => {
    setEditing(s);
    setForm({ code: s.code, name: s.name, sequenceNo: s.sequenceNo, isActive: s.isActive });
    setModalOpen(true);
  };

  const handleSave = async () => {
    if (!form.code.trim() || !form.name.trim()) {
      dispatch(addToast({ message: 'Vui lòng nhập mã và tên công đoạn', type: 'error' }));
      return;
    }
    setSaving(true);
    try {
      if (editing) {
        await sxService.updateStage(editing.id, {
          name: form.name.trim(),
          sequenceNo: Number(form.sequenceNo),
          isActive: form.isActive,
        });
        dispatch(addToast({ message: 'Cập nhật công đoạn thành công', type: 'success' }));
      } else {
        await sxService.createStage({
          code: form.code.trim(),
          name: form.name.trim(),
          sequenceNo: Number(form.sequenceNo),
        });
        dispatch(addToast({ message: 'Tạo công đoạn thành công', type: 'success' }));
      }
      setModalOpen(false);
      load();
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const filtered = stages.filter(
    s =>
      !search ||
      s.code.toLowerCase().includes(search.toLowerCase()) ||
      s.name.toLowerCase().includes(search.toLowerCase()),
  );

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-cogs" /> Quản lý công đoạn</h1>
        </div>
        <div className={styles.headerActions}>
          <Button variant="primary" onClick={openAdd}><i className="fas fa-plus" /> Thêm công đoạn</Button>
        </div>
      </div>

      <div className={styles.filtersBar} data-testid={`erp-cong-doan-filters`}>
        <Input placeholder="Tìm công đoạn..." value={searchDraft} onChange={e => setSearchDraft(e.target.value)} size="small" />
        <ListSearchRefreshButtons testIdPrefix="erp-cong-doan" onSearch={handleSearch} onRefresh={refresh} showSearch={true} />
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : filtered.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Chưa có công đoạn</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Mã</th>
                  <th>Tên công đoạn</th>
                  <th className={styles.colRight}>Thứ tự</th>
                  <th>Trạng thái</th>
                  <th className={styles.colActions}></th>
                </tr>
              </thead>
              <tbody>
                {filtered.map(s => (
                  <tr key={s.id}>
                    <td><code>{s.code}</code></td>
                    <td>{s.name}</td>
                    <td className={styles.colRight}>{s.sequenceNo}</td>
                    <td>
                      <span className={s.isActive ? styles.tagSuccess : styles.tagDefault}>
                        {s.isActive ? 'Dùng' : 'Ngưng'}
                      </span>
                    </td>
                    <td className={styles.colActions}>
                      <button type="button" className={styles.actionBtn} onClick={() => openEdit(s)} title="Sửa">
                        <i className="fas fa-edit" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      <Modal isOpen={modalOpen} onClose={() => setModalOpen(false)} title={editing ? 'Sửa công đoạn' : 'Thêm công đoạn'}>
        <div className={styles.modalBody}>
          <div className={styles.field}>
            <label className={styles.label}>Mã *</label>
            <Input value={form.code} onChange={e => setForm(p => ({ ...p, code: e.target.value }))} disabled={!!editing} />
          </div>
          <div className={styles.field}>
            <label className={styles.label}>Tên *</label>
            <Input value={form.name} onChange={e => setForm(p => ({ ...p, name: e.target.value }))} />
          </div>
          <div className={styles.field}>
            <label className={styles.label}>Thứ tự</label>
            <Input type="number" min={1} value={String(form.sequenceNo)} onChange={e => setForm(p => ({ ...p, sequenceNo: Number(e.target.value) }))} />
          </div>
          {editing && (
            <div className={styles.field}>
              <label className={styles.label}>Trạng thái</label>
              <select value={form.isActive ? 'true' : 'false'} onChange={e => setForm(p => ({ ...p, isActive: e.target.value === 'true' }))}>
                <option value="true">Dùng</option>
                <option value="false">Ngưng</option>
              </select>
            </div>
          )}
        </div>
        <div className={styles.modalActions}>
          <Button variant="secondary" onClick={() => setModalOpen(false)}>Huỷ</Button>
          <Button variant="primary" onClick={handleSave} disabled={saving}>{saving ? 'Đang lưu...' : 'Lưu'}</Button>
        </div>
      </Modal>
    </div>
  );
};

export default CongDoanPage;
